import { CircleAlert } from "lucide-react";
import { Fragment } from "react";

import { Alert, AlertTitle, AlertDescription } from "@/components/ui/alert";

export interface ErrorProps {
  title?: string;
  description?: string;
  error?: Error;
}

export const AlertError = (props: ErrorProps) => {
  const { title, description, error } = props;
  return (
    <Fragment>
      <div>
        <Alert variant="destructive">
          <CircleAlert
            size={16}
            className="mr-2"
          />
          <AlertTitle>{title ?? "Error"}</AlertTitle>
          {(error?.message || description) && (
            <AlertDescription>{error?.message || description}</AlertDescription>
          )}
        </Alert>
      </div>
    </Fragment>
  );
};

import { Check, Copy } from "lucide-react";

import { Button } from "@/components/ui/button";

import { useCopyToClipboard } from "./use-copy-to-clipboard";

import type { ComponentProps } from "react";

export function ButtonCopy({
  content,
  children,
  ...props
}: ComponentProps<typeof Button> & { content: string }) {
  const { copyToClipboard, isCopied } = useCopyToClipboard();

  return (
    <Button
      {...props}
      onClick={() => copyToClipboard(content)}
    >
      {isCopied ? <Check /> : <Copy />}
      {children}
    </Button>
  );
}

import { Button } from "@/components/ui/button";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";

import type { ComponentProps } from "react";

export function ButtonTooltip({
  disabled,
  children,
  tooltip,
  disabledTooltip,
  ...props
}: ComponentProps<typeof Button> & {
  tooltip: string;
  disabledTooltip?: string;
}) {
  return (
    <Tooltip>
      <TooltipTrigger
        asChild
        className="cursor-not-allowed"
      >
        <span tabIndex={0}>
          <Button
            {...props}
            disabled={disabled}
            style={{
              pointerEvents: disabled ? "none" : "auto",
            }}
          >
            {children}
          </Button>
        </span>
      </TooltipTrigger>
      <TooltipContent>
        <p>{disabled ? (disabledTooltip ?? tooltip) : tooltip}</p>
      </TooltipContent>
    </Tooltip>
  );
}

import { useState, type ReactNode } from "react";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";

export interface FsDialogProps {
  title: ReactNode;
  description?: ReactNode;
  trigger?: ReactNode;
  children?: ReactNode;
  open?: boolean;
  actions?: {
    left?: ReactNode;
    right?: ReactNode;
  };
  hideFooter?: boolean;
  contentClassName?: string;
  hideCloseButton?: boolean;
  onOpenChange?: (open: boolean) => void;
}

export const FsDialog = ({
  title,
  description,
  trigger,
  children,
  open: controlledOpen,
  actions,
  hideFooter,
  contentClassName,
  hideCloseButton,
  onOpenChange,
}: FsDialogProps) => {
  const isControlled = controlledOpen !== undefined;
  const [internalOpen, setInternalOpen] = useState<boolean>(false);
  const open = isControlled ? controlledOpen : internalOpen;

  const handleOpenChange = (newOpen: boolean) => {
    if (!isControlled) {
      setInternalOpen(newOpen);
    }
    onOpenChange?.(newOpen);
  };

  return (
    <Dialog
      open={open}
      onOpenChange={handleOpenChange}
    >
      {trigger && <DialogTrigger asChild>{trigger}</DialogTrigger>}
      <DialogContent
        showCloseButton={!hideCloseButton}
        className={cn(
          "flex max-h-[90vh] flex-col gap-0 overflow-hidden p-0 md:h-[540px] md:max-h-[min(540px,90vh)] md:max-w-[700px] lg:max-w-[800px]",
          contentClassName,
        )}
        onCloseAutoFocus={(event) => {
          event.preventDefault();
          document.body.style.pointerEvents = "";
        }}
      >
        <DialogHeader
          className={cn(
            "bg-sidebar shrink-0 gap-1.5 border-b p-3",
            description ? "" : "gap-0",
          )}
        >
          <DialogTitle>{title}</DialogTitle>
          {description ? (
            <DialogDescription>{description}</DialogDescription>
          ) : (
            <DialogDescription />
          )}
        </DialogHeader>
        <div className="flex flex-1 flex-col overflow-y-auto p-0">
          {children}
        </div>
        {!hideFooter && (
          <DialogFooter className="bg-sidebar justify-between border-t p-3 sm:justify-between">
            {actions?.left}
            <div className="ml-auto flex items-center justify-center gap-2">
              {actions?.right}
              <DialogClose asChild>
                <Button
                  variant="outline"
                  size="sm"
                  className="ml-auto cursor-pointer"
                >
                  Close
                </Button>
              </DialogClose>
            </div>
          </DialogFooter>
        )}
      </DialogContent>
    </Dialog>
  );
};

import { CornerDownLeft, FileCode2, RefreshCcw } from "lucide-react";
