import { Field, FieldError, FieldLabel } from "@/components/ui/field";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupButton,
  InputGroupText,
  InputGroupTextarea,
} from "@/components/ui/input-group";

import { ButtonCopy } from "./button-copy";

import type { ReactNode, SyntheticEvent } from "react";

export const FieldCodeInput = ({
  isInvalid,
  name,
  label,
  value,
  errors,
  onChange,
  onBlur,
  onRefresh,
  onRun,
}: {
  isInvalid: boolean;
  name: string;
  label: ReactNode;
  value: string | undefined;
  errors?: (
    | {
        message?: string;
      }
    | undefined
  )[];
  onChange: (value: string) => void;
  onBlur: () => void;
  onRefresh?: () => void;
  onRun?: () => void;
}) => {
  const [cursorPosition, setCursorPosition] = useState({ line: 1, column: 1 });

  const handleCursorChange = (e: SyntheticEvent<HTMLTextAreaElement>) => {
    const target = e.currentTarget;
    const selectionStart = target.selectionStart;
    const textBeforeCursor = target.value.substring(0, selectionStart);
    const lines = textBeforeCursor.split("\n");
    const line = lines.length;
    const column = (lines.at(-1)?.length ?? 0) + 1;

    setCursorPosition({ line, column });
  };

  return (
    <Field data-invalid={isInvalid}>
      <FieldLabel htmlFor={name}>{label}</FieldLabel>

      <InputGroup>
        <InputGroupTextarea
          placeholder={`$context.Value("user").ID`}
          className="min-h-[150px]"
          id={name}
          name={name}
          value={value}
          onBlur={onBlur}
          onChange={(e) => onChange(e.target.value)}
          onSelect={handleCursorChange}
          onClick={handleCursorChange}
          onKeyUp={handleCursorChange}
          aria-invalid={isInvalid}
        />
        <InputGroupAddon
          align="block-end"
          className="border-t"
        >
          <InputGroupText>
            Line {cursorPosition.line}, Column {cursorPosition.column}
          </InputGroupText>
          {onRun && (
            <InputGroupButton
              size="sm"
              className="ml-auto"
              variant="default"
            >
              Run <CornerDownLeft />
            </InputGroupButton>
          )}
        </InputGroupAddon>
        <InputGroupAddon
          align="block-start"
          className="border-b"
        >
          <InputGroupText className="font-mono font-medium">
            <FileCode2 />
            {name}
          </InputGroupText>
          {onRefresh && (
            <InputGroupButton
              className="ml-auto"
              size="icon-xs"
              onClick={onRefresh}
            >
              <RefreshCcw />
            </InputGroupButton>
          )}
          <InputGroupButton
            className={onRefresh ? "" : "ml-auto"}
            variant="ghost"
            size="icon-xs"
            asChild
          >
            <ButtonCopy
              className="cursor-pointer"
              variant="ghost"
              size="icon"
              content={value ?? ""}
            />
          </InputGroupButton>
        </InputGroupAddon>
      </InputGroup>

      {isInvalid && <FieldError errors={errors} />}
    </Field>
  );
};

