import type React from "react";

declare global {
  interface Window {
    LinkComponent: React.ComponentType<React.ComponentProps<"a">> | undefined;
    navigateFunction: ((url: string) => void) | undefined;
  }

  var LinkComponent: React.ComponentType<React.ComponentProps<"a">> | undefined;
  var navigateFunction: ((url: string) => void) | undefined;
}

export const setGlobalLinkComponent = (
  LinkComponent: React.ComponentType<React.ComponentProps<"a">>,
) => {
  if (window !== undefined) {
    window.LinkComponent = LinkComponent;
  }

  if (globalThis !== undefined) {
    globalThis.LinkComponent = LinkComponent;
  }
};

export const getGlobalLinkComponent = (): React.ComponentType<
  React.ComponentProps<"a">
> => {
  return (
    window.LinkComponent ??
    (({ children, href, ...linkProps }) => (
      <a
        href={href}
        {...linkProps}
      >
        {children}
      </a>
    ))
  );
};

export const setGlobalNavigateFunction = (
  navigateFunction: (url: string) => void,
) => {
  if (window !== undefined) {
    window.navigateFunction = navigateFunction;
  }

  if (globalThis !== undefined) {
    globalThis.navigateFunction = navigateFunction;
  }
};

export const getGlobalNavigateFunction = (): ((url: string) => void) => {
  return (
    window.navigateFunction ??
    ((url: string) => {
      window.location.href = url;
    })
  );
};

