} from "@/components/ui/popover";

export const PopConfirm = ({
  children,
  title = "Are you absolutely sure?",
  description,
  modal,
  onConfirm,
  onCancel,
}: {
  children: ReactNode;
  title?: ReactNode;
  description?: ReactNode;
  modal?: boolean;
  onConfirm?: () => void;
  onCancel?: () => void;
}) => {
  const [open, setOpen] = useState(false);

  const handleCancel = () => {
    onCancel?.();
    setOpen(false);
  };

  const handleConfirm = () => {
    onConfirm?.();
    setOpen(false);
  };

  return (
    <Popover
      open={open}
      onOpenChange={setOpen}
      modal={modal}
    >
      <PopoverTrigger asChild>{children}</PopoverTrigger>
      <PopoverContent
        className="group/popconfirm w-auto"
        sideOffset={0}
        alignOffset={0}
        align="end"
        onOpenAutoFocus={(event) => event.preventDefault()}
      >
        <div className="space-y-4 text-sm">
          <div className="space-y-2">
            <div className="flex items-center gap-2 font-medium">{title}</div>
            {description && (
              <p className="text-muted-foreground text-sm">{description}</p>
            )}
          </div>
          <div className="flex justify-end space-x-2">
            <Button
              variant="outline"
              size="sm"
              onClick={handleCancel}
              className="h-auto cursor-pointer px-2.5 py-1.5 text-xs"
            >
              No
            </Button>
            <Button
              size="sm"
              onClick={handleConfirm}
              className="h-auto cursor-pointer px-2.5 py-1 text-xs"
            >
              Yes
            </Button>
          </div>
        </div>
        <PopoverPrimitive.Arrow className="bg-popover fill-popover z-50 size-2.5 translate-y-[calc(-50%_-_0px)] rotate-45 rounded-[2px] border-r-1 border-b-1 shadow-lg" />
      </PopoverContent>
    </Popover>
  );
};

