export type SchemaViewType<
  TZones extends Record<string, string> = Record<string, string>,
> = {
  id: string;
  name: string;
  icon: ReactNode;
  zones: TZones;
  render: (
    props: ComponentProps<"div"> & {
      zones: Record<keyof TZones, ReactNode>;
    },
  ) => ReactNode;
};

export type ViewType = SchemaViewType<Record<string, string>>;

export const defineLayout = <TZones extends Record<string, string>>(
  layout: SchemaViewType<TZones>,
): SchemaViewType<TZones> => {
