};

export const getDefaultZone = <
  TView extends SchemaViewType<Record<string, string>>,
>(
  view: TView,
): keyof TView["zones"] => {
  if ("main" in view.zones) {
    return "main" as keyof TView["zones"];
  }
  return Object.keys(view.zones)[0] as keyof TView["zones"];
};

