import { dequal as deepEqual } from "dequal/lite";

import { getDefaultZone, schemaContentViews } from "./schema-view";

import type { SchemaDefinition, ZoneFieldSettings } from "fastschema";

export const populateActiveFormViewSettings = (
  schemaDefinition: SchemaDefinition,
): {
  zones: Record<string, ZoneFieldSettings[]>;
  needsUpdate: boolean;
} => {
  const view =
    schemaContentViews.find(
      (v) => v.id === schemaDefinition?.settings?.form?.active_view,
    ) || schemaContentViews[0];

  const defaultZone = getDefaultZone(view);
  const allFieldNames = (schemaDefinition.fields || []).map((f) => f.name);
  const existingViewConfig =
    schemaDefinition.settings?.form?.views?.[view.id] || {};

  const zones = Object.keys(view.zones).reduce(
    (acc, zoneKey) => {
      const existingZone = existingViewConfig[zoneKey];
      // Use existing zone if it exists and has data, otherwise initialize
      if (Array.isArray(existingZone) && existingZone.length > 0) {
        acc[zoneKey] = existingZone;
      } else {
        // Initialize with default field settings (no renderer/options = use defaults)
        acc[zoneKey] =
          zoneKey === defaultZone
            ? allFieldNames.map((fieldName) => ({ field: fieldName }))
            : [];
      }
      return acc;
    },
    {} as Record<string, ZoneFieldSettings[]>,
  );

  // Find fields that are not in any zone
  const fieldsInZones = new Set(
    Object.values(zones)
      .flat()
      .map((item) => item.field),
  );
  const missingFields = allFieldNames.filter(
    (fieldName) => !fieldsInZones.has(fieldName),
  );

  // Add missing fields to the default zone
  if (missingFields.length > 0) {
    zones[defaultZone] = [
      ...zones[defaultZone],
      ...missingFields.map((fieldName) => ({ field: fieldName })),
    ];
  }

  // Check if the zones we created are different from what exists
  const needsUpdate = !deepEqual(zones, existingViewConfig);

  return { zones, needsUpdate };
};

export const populateActiveListViewSettings = (
  schemaDefinition: SchemaDefinition,
) => {
  const activeView = schemaDefinition?.settings?.list?.active_view || "default";

  return (
    schemaDefinition?.settings?.list?.views?.[activeView] ||
    schemaDefinition.fields.map((field) => ({
      field: field.name,
      filterable: true,
      sortable: true,
    }))
  );
};

export const ensureSchemaDefinition = (schemaDefinition: SchemaDefinition) => {
  // Populate server_name for every field.
  // server_name is used to indicate that the field name has been renamed from its original name.
  schemaDefinition.fields = schemaDefinition.fields.map((field) => {
    field.server_name = field.server_name || field.name;
    return field;
  });

  schemaDefinition.settings = schemaDefinition.settings || {};

  // Prepare form view settings
  schemaDefinition.settings.form = schemaDefinition.settings.form || {};
  schemaDefinition.settings.form.active_view =
    schemaDefinition.settings.form.active_view || schemaContentViews[0].id;
  schemaDefinition.settings.form.hidden_fields =
    schemaDefinition.settings.form.hidden_fields || [];
  schemaDefinition.settings.form.views =
    schemaDefinition.settings.form.views || {};

  const { zones } = populateActiveFormViewSettings(schemaDefinition);
  schemaDefinition.settings.form.views[
    schemaDefinition.settings.form.active_view
  ] = zones;

  // Prepare list view settings
  schemaDefinition.settings.list = schemaDefinition.settings.list || {};
  schemaDefinition.settings.list.active_view =
    schemaDefinition.settings.list.active_view || "default";
  schemaDefinition.settings.list.views =
    Object.keys(schemaDefinition.settings.list.views || {}).length > 0
      ? schemaDefinition.settings.list.views
      : {
          default: populateActiveListViewSettings(schemaDefinition),
        };

  return schemaDefinition;
};

import { useEffect, useState, type ComponentType } from "react";

