export type TabDialogItem = {
  name: string;
  icon?: ComponentType<{ className?: string }>;
  Component: ComponentType;
};

export interface TabDialogProps extends FsDialogProps {
  tabs: TabDialogItem[];
}

export const TabDialog = ({
  title,
  description,
  tabs,
  trigger,
  children,
  open: defaultOpen,
  onOpenChange,
  actions,
}: TabDialogProps) => {
  const [open, setOpen] = useState<boolean>(!!defaultOpen);
  const [activeTab, setActiveTab] = useState(tabs?.[0]?.name);
  const ActiveComponent =
    tabs.find((item) => item.name === activeTab)?.Component ?? (() => <div />);

  // Sync internal state with controlled open prop
  useEffect(() => {
    setOpen(!!defaultOpen);
  }, [defaultOpen]);

  const handleOpenChange = (newOpen: boolean) => {
    setOpen(newOpen);
    onOpenChange?.(newOpen);
  };

  return (
    <FsDialog
      trigger={trigger}
      title={title}
      description={description}
      open={open}
      onOpenChange={handleOpenChange}
      actions={actions}
    >
      <div className="flex min-h-0 flex-1">
        <aside className="bg-sidebar hidden w-48 shrink-0 flex-col overflow-y-auto border-r md:flex">
          <nav className="flex flex-col gap-1 p-1">
            {tabs.map((item) => {
              const Icon = item.icon;
              return (
                <button
                  key={item.name}
                  onClick={() => setActiveTab(item.name)}
                  className={cn(
                    "flex cursor-pointer items-center gap-3 rounded-md px-3 py-2 text-sm font-medium transition-colors",
                    activeTab === item.name
                      ? "bg-sidebar-accent text-sidebar-accent-foreground"
                      : "hover:bg-sidebar-accent/50 text-sidebar-foreground",
                  )}
                  type="button"
                >
                  {Icon && <Icon className="h-4 w-4" />}
                  <span>{item.name}</span>
                </button>
              );
            })}
          </nav>
        </aside>
        <main className="flex min-h-0 flex-1 flex-col">
          <div className="flex flex-1 flex-col overflow-y-auto p-4">
            <ActiveComponent />
          </div>
          {children}
        </main>
      </div>
    </FsDialog>
  );
};

import * as React from "react";

export function useCopyToClipboard({
  timeout = 2000,
  onCopy,
}: {
  timeout?: number;
  onCopy?: () => void;
} = {}) {
  const [isCopied, setIsCopied] = React.useState(false);

  const copyToClipboard = (value: string) => {
    if (typeof window === "undefined" || !navigator.clipboard.writeText) {
      return;
    }

    if (!value) return;

    navigator.clipboard.writeText(value).then(() => {
      setIsCopied(true);

      if (onCopy) {
        onCopy();
      }

      if (timeout !== 0) {
        setTimeout(() => {
          setIsCopied(false);
        }, timeout);
      }
      // eslint-disable-next-line no-console
    }, console.error);
  };

  return { isCopied, copyToClipboard };
}

export const titleCase = (str: string) => {
  const splitStr = str.toLowerCase().split(" ");

  for (let i = 0; i < splitStr.length; i++) {
    splitStr[i] =
      splitStr[i].charAt(0).toUpperCase() + splitStr[i].substring(1);
  }

  return splitStr.join(" ");
};

export const slugToTitle = (str: string) => {
  return titleCase(str.replace(/[-_]/g, " "));
};

/**
 * Inserts an item into an array before the target index, or appends if not found.
 */
export const insertBefore = <T>(
  array: T[],
  item: T,
  findTarget: (item: T) => boolean,
): T[] => {
  const targetIndex = array.findIndex(findTarget);
  const result = [...array];

  if (targetIndex === -1) {
    result.push(item);
  } else {
    result.splice(targetIndex, 0, item);
  }

  return result;
};

/**
 * Maps object entries while preserving order.
 */
export const mapEntries = <K extends string, V, R>(
  obj: Record<K, V>,
  fn: (key: K, value: V) => [string, R],
): Record<string, R> =>
  Object.fromEntries(Object.entries(obj).map(([k, v]) => fn(k as K, v as V)));
